84	func validateAndApplyPreClaimIntakeRewrite(original *bead.Bead, rewrite PreClaimIntakeRewrite) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, error) {
85		if original == nil {
86			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: bead required")
87		}
88	
89		normalized := PreClaimIntakeRewrite{
90			Description:   strings.TrimSpace(rewrite.Description),
91			Acceptance:    strings.TrimSpace(rewrite.Acceptance),
92			ChangedFields: normalizePreClaimIntakeRewriteFields(rewrite.ChangedFields),
93		}
94		if len(normalized.ChangedFields) == 0 {
95			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: missing changed_fields")
96		}
97	
98		allowed := map[string]struct{}{
99			"description": {},
100			"acceptance":  {},
101		}
102		for _, field := range normalized.ChangedFields {
103			if _, ok := allowed[field]; !ok {
104				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: unsafe field %q", field)
105			}
106		}
107	
108		before := snapshotPreClaimIntakeRewrite(original.Description, original.Acceptance)
109	
110		oldDescription := strings.TrimSpace(original.Description)
111		if hasString(normalized.ChangedFields, "description") {
112			if normalized.Description == "" {
113				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: description rewrite missing")
114			}
115			if strings.EqualFold(strings.TrimSpace(normalized.Description), oldDescription) {
116				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: description unchanged")
117			}
118			if oldDescription != "" {
119				if !strings.Contains(normalizeWhitespace(normalized.Description), normalizeWhitespace(oldDescription)) {
120					return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: description must preserve original text")
121				}
122			}
123		} else if normalized.Description != "" {
124			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: description supplied without changed_fields")
125		}
126	
127		oldAcceptance := strings.TrimSpace(original.Acceptance)
128		if hasString(normalized.ChangedFields, "acceptance") {
129			if normalized.Acceptance == "" {
130				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: acceptance rewrite missing")
131			}
132			if strings.EqualFold(strings.TrimSpace(normalized.Acceptance), oldAcceptance) {
133				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: acceptance unchanged")
134			}
135			if !acceptancePreservesCriteria(oldAcceptance, normalized.Acceptance) {
136				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: acceptance criteria dropped or altered")
137			}
138		} else if normalized.Acceptance != "" {
139			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, fmt.Errorf("pre-claim intake rewrite: acceptance supplied without changed_fields")
140		}
141	
142		afterDescription := oldDescription
143		if containsString(normalized.ChangedFields, "description") {
144			afterDescription = normalized.Description
145		}
146		afterAcceptance := oldAcceptance
147		if containsString(normalized.ChangedFields, "acceptance") {
148			afterAcceptance = normalized.Acceptance
149		}
150		after := snapshotPreClaimIntakeRewrite(afterDescription, afterAcceptance)
151		return normalized, before, after, nil
152	}
